  "Isabella Yang":                      "isabella",
  "Gwenne Manares":                     "gwenne",
  "Gwenne Jane Manares":                "gwenne",
  "Komal Kaur":                         "komal",
  "Komal Preet Kaur":                   "komal",
  "Jemma Read":                         "jemma",
  // First-name variants
  "Jade":      "jade",
  "Alistair":  "alistair",
