function getPortalId() {
  if (!APP.user?.name) return null;
  const name = APP.user.name.trim();
  if (NAME_TO_ID[name]) return NAME_TO_ID[name];
  const lower = name.toLowerCase();
  for (const [k,v] of Object.entries(NAME_TO_ID)) {
    if (k.toLowerCase() === lower) return v;
  }
  const first = name.split(" ")[0].toLowerCase();
  for (const [k,v] of Object.entries(NAME_TO_ID)) {
    if (k.toLowerCase() === first || k.toLowerCase().startsWith(first + " ")) return v;
  }
  return null;
}

// ── CERTS ─────────────────────────────────────────────────────
const MY_CERTS = [
  { key:"apc",           label:"APC 2025/2026",               renews:"Annual — 1 April",  icon:"📋", required:true  },
  { key:"firstaid",      label:"First Aid / CPR",              renews:"Every 2 years",     icon:"🏥", required:true  },
  { key:"cultural",      label:"Cultural Competency (Māori)",  renews:"Annual",            icon:"🌿", required:true  },
  { key:"policevetting", label:"Police Vetting",               renews:"Every 3 years",     icon:"🚔", required:true  },
  { key:"peerreview",    label:"Peer Review",                  renews:"Annual",            icon:"🔍", required:false },
  { key:"appraisal",     label:"Performance Appraisal",        renews:"Annual",            icon:"📊", required:false },
];
let _certFiles = {}, _certScan = {}, _certReady = false;

function certStoreKey(k){ const pid=getPortalId(); return pid?`cert_${pid}_${k}`:null; }

function getExpiryStatus(s){
  if(!s) return null;
  const exp=new Date(s), today=new Date();
  const d=Math.ceil((exp-today)/(1000*60*60*24));
  if(d<0)   return{status:"expired",  label:"Expired "+exp.toLocaleDateString("en-NZ"),                          color:"var(--red)"};
  if(d<=60) return{status:"expiring", label:"Expires "+exp.toLocaleDateString("en-NZ")+" ("+d+"d)",              color:"var(--amber)"};
  return          {status:"valid",    label:"Valid to "+exp.toLocaleDateString("en-NZ"),                          color:"var(--green)"};
}

async function loadMyCerts(){
  const pid=getPortalId();
  if(!pid){_certReady=true;renderCertsSection();return;}
  try{
    const r=await fetch(PORTAL_API+"/store",{headers:{"X-Portal-Secret":PORTAL_SECRET}});
    if(!r.ok) throw new Error();
    const state=await r.json();
    const files={...(state.files||{}),...(state.data||{})};
    MY_CERTS.forEach(cert=>{
      const k=certStoreKey(cert.key), expK=k?"expiry_"+k:null;
      if(k&&files[k]){
        _certFiles[cert.key]={..._certFiles[cert.key],...files[k]};
        if(expK&&files[expK]?.expiry&&!_certFiles[cert.key].expiry) _certFiles[cert.key].expiry=files[expK].expiry;
      }
    });
  }catch(e){_warn("[Certs]",e.message);}
  _certReady=true; renderCertsSection();
}

async function detectExpiry(key,dataUrl,label){
  try{
    const r=await fetch(PORTAL_API+"/detect-expiry",{method:"POST",headers:_ph,body:JSON.stringify({fileData:dataUrl,certLabel:label})});
    if(!r.ok) return null;
    return(await r.json()).expiry||null;
  }catch(e){return null;}
}

async function handleCertUpload(certKey,inputEl){
  const file=inputEl.files[0]; inputEl.value="";
  if(!file) return;
  if(file.size>3*1024*1024){alert("File too large — maximum 3 MB.");return;}
  const pid=getPortalId();
  if(!pid){alert("Could not match your account to a staff profile. Contact Jade.");return;}
  const reader=new FileReader();
  reader.onload=async function(ev){
    const dataUrl=ev.target.result, storeKey=certStoreKey(certKey), cert=MY_CERTS.find(c=>c.key===certKey);
    _certFiles[certKey]={fileName:file.name,fileType:file.type,dataUrl,uploadedDate:new Date().toLocaleDateString("en-NZ"),expiry:null};
    _certScan[certKey]=true; renderCertsSection();
    try{
      const up=await fetch(PORTAL_API+"/upload",{method:"POST",headers:_ph,body:JSON.stringify({fileKey:storeKey,fileName:file.name,fileType:file.type,fileData:dataUrl})});
      const res=await up.json();
      if(res.ok&&res.file){
        _certFiles[certKey]={..._certFiles[certKey],...res.file};
        await fetch(PORTAL_API+"/store",{method:"POST",headers:_ph,body:JSON.stringify({key:storeKey,value:_certFiles[certKey],store:"files"})});
      }
    }catch(e){}
    const expiry=await detectExpiry(certKey,dataUrl,cert?.label||certKey);
    if(expiry){
      _certFiles[certKey].expiry=expiry;
      try{
        await fetch(PORTAL_API+"/store",{method:"POST",headers:_ph,body:JSON.stringify({key:"expiry_"+storeKey,value:{expiry}})});
        await fetch(PORTAL_API+"/store",{method:"POST",headers:_ph,body:JSON.stringify({key:storeKey,value:_certFiles[certKey],store:"files"})});
      }catch(e){}
    }
    _certScan[certKey]=false; renderCertsSection();
  };
  reader.readAsDataURL(file);
}

function triggerCertUpload(k){const i=document.getElementById("cinput-"+k);if(i)i.click();}
function viewCert(k){const f=_certFiles[k];if(f){const u=f.blobUrl||f.dataUrl;if(u)window.open(u,"_blank");}}
function removeCert(k){
  if(!confirm("Remove this document?"))return;
  const sk=certStoreKey(k); delete _certFiles[k];
  if(sk) fetch(PORTAL_API+"/upload?fileKey="+encodeURIComponent(sk),{method:"DELETE",headers:{"X-Portal-Secret":PORTAL_SECRET}}).catch(()=>{});
  renderCertsSection();
}
function renderCertsSection(){const el=document.getElementById("certs-section");if(el)el.innerHTML=buildCertsHtml();}
function buildCertCard(cert){
  const f=_certFiles[cert.key], scanning=_certScan[cert.key], expInfo=f?.expiry?getExpiryStatus(f.expiry):null;
  let cc="cert-card",pc="cert-pill",pl="";
  if(!f){cc+=cert.required?" cert-required":"";pc+=cert.required?" required":" optional";pl=cert.required?"Required ⚠":"Optional";}
  else if(scanning){cc+=" cert-ok";pc+=" scanning";pl="🔍 Reading…";}
  else if(expInfo?.status==="expired"){cc+=" cert-expired";pc+=" expired";pl="Expired ⚠";}
  else if(expInfo?.status==="expiring"){cc+=" cert-expiring";pc+=" expiring";pl="Expiring ⏰";}
  else{cc+=" cert-ok";pc+=" ok";pl="On file ✓";}
  const fi=f?`<div style="font-size:10px;color:var(--dim);margin-top:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">📄 ${f.fileName} · ${f.uploadedDate}</div>`:"";
  const el=expInfo?`<div style="font-size:11px;color:${expInfo.color};margin-top:4px;font-weight:600">${expInfo.status==="expired"?"⚠ ":expInfo.status==="expiring"?"⏰ ":"✓ "}${expInfo.label}</div>`:"";
  const vb=f?`<button class="cert-btn view" onclick="viewCert('${cert.key}')">👁 View</button>`:"";
  const ub=`<button class="cert-btn upload" onclick="triggerCertUpload('${cert.key}')">${f?"📷 Update":"📷 Upload"}</button>`;
  const rb=f?`<button class="cert-btn remove" onclick="removeCert('${cert.key}')">Remove</button>`:"";
  return`<div class="${cc}"><div style="display:flex;align-items:flex-start;justify-content:space-between;gap:10px"><div style="flex:1;min-width:0"><div style="display:flex;align-items:center;gap:7px"><span style="font-size:18px">${cert.icon}</span><span style="font-size:13px;font-weight:600">${cert.label}</span></div><div style="font-size:10px;color:var(--muted);margin-top:2px">${cert.renews}</div>${fi}${el}</div><span class="${pc}" style="flex-shrink:0">${pl}</span></div><div style="display:flex;gap:5px;margin-top:10px;flex-wrap:wrap">${vb}${ub}${rb}</div><input id="cinput-${cert.key}" type="file" accept="image/*,application/pdf" style="display:none" onchange="handleCertUpload('${cert.key}',this)"></div>`;
}
function buildCertsHtml(){
  const pid=getPortalId();
  // Org docs section (always shown - doesn't require portal profile link)
  const orgDocsSection=`
    <div style="font-size:12px;font-weight:700;color:var(--text);margin-bottom:10px;display:flex;align-items:center;gap:6px">
      🏢 Organisation Documents
      ${APP.user?.role==="owner"?'<span style="font-size:10px;font-weight:500;color:var(--accent);background:var(--accentL);padding:2px 7px;border-radius:10px">Owner: you can upload</span>':""}
    </div>
    <div id="org-docs-section">${buildOrgDocsHtml()}</div>
    <div style="height:1px;background:var(--border);margin:18px 0"></div>
    <div style="font-size:12px;font-weight:700;color:var(--text);margin-bottom:10px">👤 My Documents</div>
  `;
  if(!pid){
    const nm=APP.user?.name||"unknown";
    return orgDocsSection+`<div class="debug-tag">⚙️ Auth returned name <strong>"${nm}"</strong> — share this with Jade to fix the mapping.</div><div style="background:var(--redBg);border:1px solid rgba(220,38,38,.2);border-radius:12px;padding:1.5rem;text-align:center"><div style="font-size:28px;margin-bottom:8px">⚠️</div><div style="font-size:14px;font-weight:600;color:var(--red)">Profile not linked</div><div style="font-size:12px;color:var(--dim);margin-top:5px;line-height:1.6">Contact Jade with the name shown above to get this fixed.</div></div>`;
  }
  if(!_certReady) return orgDocsSection+`<div class="empty-state"><div class="spinner" style="margin:0 auto"></div><div style="font-size:13px;margin-top:8px">Loading your documents…</div></div>`;
  const req=MY_CERTS.filter(c=>c.required);
  const done=req.filter(c=>{const f=_certFiles[c.key];if(!f)return false;if(f.expiry&&getExpiryStatus(f.expiry).status==="expired")return false;return true;});
  const pct=req.length>0?Math.round((done.length/req.length)*100):0;
  const bc=pct===100?"var(--green)":pct>=50?"var(--amber)":"var(--red)";
  return orgDocsSection+`<div class="cert-progress-wrap"><div style="display:flex;align-items:center;justify-content:space-between"><div><div style="font-size:14px;font-weight:700">${pct===100?"✅ All required docs on file":"📋 Required documents"}</div><div style="font-size:11px;color:var(--muted);margin-top:2px">${done.length} of ${req.length} uploaded and current</div></div><div style="font-size:24px;font-weight:700;color:${bc}">${pct}%</div></div><div class="cert-prog-bg"><div class="cert-prog-fill" style="width:${pct}%;background:${bc}"></div></div></div><div style="background:var(--accentL);border:1px solid rgba(27,107,74,.2);border-radius:10px;padding:11px 13px;margin-bottom:14px;font-size:11px;color:var(--accentD);line-height:1.6">📋 Docs sync to the TBP Compliance Portal — Jade can see them as soon as you upload. Max 3 MB per file.</div>`+MY_CERTS.map(c=>buildCertCard(c)).join("");
}

// ── CPD ───────────────────────────────────────────────────────
const CPD_CATEGORIES = [
  {key:"inservice",   icon:"🏫", label:"In-service Training"},
  {key:"course",      icon:"🎓", label:"Course / Workshop"},
  {key:"online",      icon:"💻", label:"Online Learning"},
  {key:"mauriora",    icon:"🌿", label:"Mauriora Cultural Competency"},
  {key:"peerreview",  icon:"👥", label:"Peer Review"},
  {key:"selfstudy",   icon:"📖", label:"Self-Directed Study"},
  {key:"conference",  icon:"📊", label:"Conference"},
  {key:"reflective",  icon:"🔄", label:"Reflective Practice"},
  {key:"other",       icon:"➕", label:"Other"},
];
const CPD_TARGET = 20; // PBNZ annual minimum (hours)
let _cpdEntries = [], _cpdReady = false, _cpdYear = new Date().getFullYear(), _cpdShowForm = false, _cpdFormType = "inservice";

// ── CPD: stored as typed entries inside the inservices array (no new keys needed) ──
// type="inservice"    → broadcast by owner, has loggedTo:[pids]
// type="personal_cpd" → added by staff, has staffId:"hans"

// Try hardest to have Drive token + file ID available before a write.
// Pulls from localStorage cache and attempts silent OAuth if needed.
async function _ensureDriveReady(){
  if (_driveToken && _driveStateFileId) return true;
  // Token: cached -> in-memory (sync)
  if (!_driveToken) {
    const cached = _kpiGetCachedToken();
    if (cached) {
      _driveToken = cached;
      try {
        await _kpiLoadGoogleScripts();
        await _kpiInitGapi();
        window.gapi.client.setToken({ access_token: cached });
      } catch {}
    }
  }
  // Token: silent OAuth attempt (works if user is signed into Google in this browser)
  if (!_driveToken) {
    try { await _kpiGetDriveToken('none'); } catch (e) {}
  }
  // File ID: cached -> in-memory
  if (!_driveStateFileId) {
    try {
      const cachedId = localStorage.getItem('tbp_kpi_file_id');
      if (cachedId) _driveStateFileId = cachedId;
    } catch {}
  }
  // File ID: look up if we have a token but no ID
  if (_driveToken && !_driveStateFileId) {
    try {
      await _kpiLoadGoogleScripts();
      await _kpiInitGapi();
      const q = `name='portal-state.json' and '${DRIVE_PORTAL_ROOT}' in parents and trashed=false`;
      const list = await window.gapi.client.drive.files.list({ q, fields: 'files(id)', spaces: 'drive' });
      if (list.result.files.length > 0) {
        _driveStateFileId = list.result.files[0].id;
        try { localStorage.setItem('tbp_kpi_file_id', _driveStateFileId); } catch {}
      }
    } catch (e) { _warn('[KPI ensureReady]', e.message || e); }
  }
  return !!(_driveToken && _driveStateFileId);
}

// Inservice log is shared with the PhysioPortal via Drive portal-state.json.
// We read from Drive AND Vercel and merge — either source may have records the
// other is missing (happens when a device writes while Drive auth is down).
// Writes always go to both stores where possible.
let _lastReadFromDrive = false;

async function readFullLog(){
  _lastReadFromDrive = false;
  let driveEntries = null, vercelEntries = null;
  // Drive
  try{
    const data = await _kpiLoadDriveState(false);
    if (data && Array.isArray(data.inservices)) {
      driveEntries = data.inservices;
      _lastReadFromDrive = true;
    }
  }catch(e){}
  // Vercel (always — even if Drive worked, Vercel may hold records we missed)
  try{
    const r=await fetch(PORTAL_API+"/store",{headers:{"X-Portal-Secret":PORTAL_SECRET}});
    if(r.ok){
      const state=await r.json();
      const all={...(state.files||{}),...(state.data||{})};
      if(Array.isArray(all["inservices"])) vercelEntries = all["inservices"];
    }
  }catch(e){}
  // Merge by id — Drive wins on conflict, but Vercel-only records are included
  if (driveEntries && vercelEntries) {
    const driveIds = new Set(driveEntries.map(e=>String(e?.id)));
    const vercelOnly = vercelEntries.filter(e=>!driveIds.has(String(e?.id)));
    return [...driveEntries, ...vercelOnly];
  }
  return driveEntries || vercelEntries || [];
}

// Merge caller's array with existing records by ID. Records in `existing` that
// aren't in `caller` are preserved — unless caller had an authoritative Drive
// read, in which case their deletes are respected.
function _mergeInservicesById(caller, existing, callerWasAuthoritative) {
  if (callerWasAuthoritative) return caller;
  const callerIds = new Set(caller.map(e=>String(e?.id)));
  const preserved = existing.filter(e=>!callerIds.has(String(e?.id)));
  return [...caller, ...preserved];
}

async function writeFullLog(arr){
  const callerAuth = _lastReadFromDrive;
  // Try HARDER to get Drive auth before giving up — uses cached token / file ID
  await _ensureDriveReady();

  // Primary: Drive portal-state.json — re-read fresh, merge, write back
  let driveOk = false, driveExisting = null;
  try{
    if (_driveStateFileId && _driveToken) {
      const readResp = await fetch(
        `https://www.googleapis.com/drive/v3/files/${_driveStateFileId}?alt=media`,
        { headers: { Authorization: `Bearer ${_driveToken}` } }
      );
      if (readResp.ok) {
        const state = await readResp.json();
        driveExisting = Array.isArray(state.inservices) ? state.inservices : [];
        state.inservices = _mergeInservicesById(arr, driveExisting, callerAuth);
        const writeResp = await fetch(
          `https://www.googleapis.com/upload/drive/v3/files/${_driveStateFileId}?uploadType=media`,
          { method: 'PATCH', headers: { Authorization: `Bearer ${_driveToken}`, 'Content-Type': 'application/json' }, body: JSON.stringify(state) }
        );
        driveOk = writeResp.ok;
      }
    }
  }catch(e){_warn("[KPI inservice Drive write]", e.message||e);}
  // Mirror to Vercel — also merge-by-id so Vercel doesn't get overwritten with partial data
  try {
    const r = await fetch(PORTAL_API+"/store",{headers:{"X-Portal-Secret":PORTAL_SECRET}});
    const state = r.ok ? await r.json() : {};
    const vercelExisting = Array.isArray(state.data?.inservices) ? state.data.inservices : [];
    // If Drive merge succeeded, use that as the truth. Otherwise merge against Vercel's existing.
    const final = driveOk && driveExisting !== null
      ? _mergeInservicesById(arr, driveExisting, callerAuth)
      : _mergeInservicesById(arr, vercelExisting, callerAuth);
    const vercelResp = await fetch(PORTAL_API+"/store",{method:"POST",headers:_ph,body:JSON.stringify({key:"inservices",value:final})});
    return { ok: driveOk || vercelResp.ok, status: vercelResp.status, json: ()=>vercelResp.json() };
  } catch(e) {
    return { ok: driveOk, status: driveOk?200:500, json: ()=>Promise.resolve({error:e.message}) };
  }
}

async function loadCPD(){
  const pid=getPortalId();
  if(!pid){_cpdReady=true;renderCPDSection();return;}
  try{
    const all=await readFullLog();
    const bc=all
      .filter(e=>e.type==="inservice"&&Array.isArray(e.loggedTo)&&e.loggedTo.includes(pid))
      .map(e=>({id:e.id,date:e.date,title:(e.title||e.topic||"Inservice"),type:"inservice",hours:e.hours,notes:e.notes||"",addedBy:"owner"}));
    const me=all
      .filter(e=>e.type==="personal_cpd"&&e.staffId===pid)
      .map(e=>({id:e.id,date:e.date,title:e.title,type:e.cpd_type||"other",hours:e.hours,notes:e.notes||"",reflective_subtype:e.reflective_subtype||null,addedBy:pid}));
    _cpdEntries=[...bc,...me].sort((a,b)=>(b.date||"").localeCompare(a.date||""));
  }catch(e){_warn("[CPD]",e.message);}
  _cpdReady=true; renderCPDSection();
}

function addCPDEntry(){
  const cpd_type=document.getElementById("cpd-type")?.value;
  const title=document.getElementById("cpd-title")?.value.trim();
  const hrs=parseFloat(document.getElementById("cpd-hours")?.value)||0;
  const date=document.getElementById("cpd-date")?.value||new Date().toISOString().split("T")[0];
  const notes=document.getElementById("cpd-notes")?.value.trim()||"";
  const reflective_subtype=cpd_type==="reflective"?(document.getElementById("cpd-reflect-sub")?.value||null):null;
  if(!title){alert("Please enter a title.");return;}
  if(!hrs||hrs<=0){alert("Please enter valid hours.");return;}
  if(cpd_type==="reflective"&&!reflective_subtype){alert("Please select the reflective statement type (Māori or General).");return;}
  const pid=getPortalId();
  if(!pid){alert("Profile not linked. Contact Jade.");return;}
  const entry={id:Date.now().toString(),date,title,type:"personal_cpd",staffId:pid,cpd_type,hours:hrs,notes,reflective_subtype};
  _cpdEntries.unshift({id:entry.id,date,title,type:cpd_type,hours:hrs,notes,reflective_subtype,addedBy:pid});
  _cpdShowForm=false; renderCPDSection();
  readFullLog().then(all=>{all.unshift(entry);return writeFullLog(all);}).catch(()=>{});
}

function removeCPDEntry(id){
  if(!confirm("Remove this CPD entry?"))return;
  _cpdEntries=_cpdEntries.filter(e=>e.id!==id); renderCPDSection();
  readFullLog().then(all=>writeFullLog(all.filter(e=>e.id!==id))).catch(()=>{});
}

function toggleCPDForm(show){_cpdShowForm=show; if(!show)_cpdFormType="inservice"; renderCPDSection();}
function updateCPDType(v){_cpdFormType=v; renderCPDSection();}

function renderCPDSection(){const el=document.getElementById("cpd-section");if(el)el.innerHTML=buildCPDHtml();}

function buildCPDHtml(){
  const pid=getPortalId();
  if(!pid) return`<div class="debug-tag">⚙️ Auth returned name <strong>"${APP.user?.name||""}"</strong> — contact Jade to fix profile mapping.</div>`;
  if(!_cpdReady) return`<div class="empty-state"><div class="spinner" style="margin:0 auto"></div><div style="font-size:13px;margin-top:8px">Loading CPD log…</div></div>`;

  // PBNZ requirement: 100 hours rolling 3 years (primary metric)
  const threeYearsAgo=new Date(); threeYearsAgo.setFullYear(threeYearsAgo.getFullYear()-3);
  const threeYrStart=threeYearsAgo.toISOString().slice(0,10);
  const rolling3Entries=_cpdEntries.filter(e=>(e.date||"")>=threeYrStart);
  const rolling3Hrs=rolling3Entries.reduce((a,e)=>a+(e.hours||0),0);
  const rolling3Pct=Math.min(Math.round((rolling3Hrs/100)*100),100);
  const r3Col=rolling3Pct>=100?"#7dd3a8":rolling3Pct>=60?"#fbbf24":"#fc8181";
  const threeYrStartLabel=threeYearsAgo.toLocaleDateString("en-NZ",{month:"short",year:"numeric"});

  // This year (secondary — useful as a pacing indicator)
  const yearStr=String(_cpdYear);
  const thisYearEntries=_cpdEntries.filter(e=>(e.date||"").startsWith(yearStr));
  const totalHrs=thisYearEntries.reduce((a,e)=>a+(e.hours||0),0);

  // Reflective statements this year (PBNZ: min 3/yr — 1 Māori + 2 general)
  const reflThisYear=thisYearEntries.filter(e=>e.type==="reflective");
  const reflMaori=reflThisYear.filter(e=>e.reflective_subtype==="maori").length;
  const reflGeneral=reflThisYear.filter(e=>e.reflective_subtype==="general").length;
  const reflOk=reflMaori>=1&&reflGeneral>=2;

  let html=`
  <div class="cpd-progress-card">
    <div class="cpd-progress-ring">
      <div>
        <div class="cpd-ring-val">${rolling3Hrs.toFixed(1)}<span style="font-size:16px;font-weight:400;opacity:.7">h</span></div>
        <div class="cpd-ring-sub">of 100h over 3 years · PBNZ requirement<br>${threeYrStartLabel} → now · ${rolling3Entries.length} entr${rolling3Entries.length===1?"y":"ies"}</div>
      </div>
      <div style="flex:1;text-align:right">
        <div style="font-size:28px;font-weight:800;opacity:${rolling3Pct>=100?1:.85}">${rolling3Pct}%</div>
        <div style="font-size:11px;opacity:.7">${rolling3Pct>=100?"✅ Requirement met":""+Math.max(0,100-rolling3Hrs).toFixed(1)+"h to go"}</div>
      </div>
    </div>
    <div class="cpd-bar-bg"><div class="cpd-bar-fill" style="width:${rolling3Pct}%;background:${r3Col}"></div></div>
  </div>

  <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px">
    <div style="background:rgba(255,255,255,0.12);border-radius:12px;padding:14px;color:#fff">
      <div style="font-size:10px;font-weight:600;opacity:.7;text-transform:uppercase;letter-spacing:.06em;margin-bottom:4px">${_cpdYear} contribution</div>
      <div style="font-size:22px;font-weight:800">${totalHrs.toFixed(1)}<span style="font-size:13px;font-weight:400;opacity:.7">h</span></div>
      <div style="font-size:10px;opacity:.7;margin-top:2px">${thisYearEntries.length} entr${thisYearEntries.length===1?"y":"ies"} this year · pace ~33h/yr</div>
      <div style="height:3px;background:rgba(255,255,255,.2);border-radius:2px;margin-top:8px;overflow:hidden">
        <div style="height:100%;width:${Math.min(100,Math.round(totalHrs/33*100))}%;background:${totalHrs>=33?"#7dd3a8":totalHrs>=20?"#fbbf24":"#fc8181"};border-radius:2px"></div>
      </div>
    </div>
    <div style="background:rgba(255,255,255,0.12);border-radius:12px;padding:14px;color:#fff">
      <div style="font-size:10px;font-weight:600;opacity:.7;text-transform:uppercase;letter-spacing:.06em;margin-bottom:4px">Reflective Statements</div>
      <div style="font-size:22px;font-weight:800">${reflThisYear.length}<span style="font-size:13px;font-weight:400;opacity:.7">/3 min</span></div>
      <div style="font-size:10px;opacity:.7;margin-top:2px">${reflMaori>=1?"✓":"✗"} Māori (${reflMaori}/1) &nbsp; ${reflGeneral>=2?"✓":"✗"} General (${reflGeneral}/2)</div>
      <div style="height:3px;background:rgba(255,255,255,.2);border-radius:2px;margin-top:8px;overflow:hidden">
        <div style="height:100%;width:${Math.min(100,Math.round(reflThisYear.length/3*100))}%;background:${reflOk?"#7dd3a8":"#fbbf24"};border-radius:2px"></div>
      </div>
    </div>
  </div>`;

  // Quick links
  html+=`<div class="section" style="margin-bottom:12px">
    <div class="section-title">🔗 CPD Quick Links</div>
    <a href="https://www.mauriora.co.nz" target="_blank" class="res-row" style="text-decoration:none;margin-bottom:6px">
      <span class="res-row-icon">🌿</span><div class="res-row-body"><div class="res-row-name">Mauriora Cultural Competency</div><div class="res-row-sub">Complete Foundation Course for annual renewal (1 year validity)</div></div><span class="res-row-arrow">↗</span>
    </a>
    <a href="https://physio.org.nz" target="_blank" class="res-row" style="text-decoration:none">
      <span class="res-row-icon">🎓</span><div class="res-row-body"><div class="res-row-name">PBNZ — Physiotherapy Board NZ</div><div class="res-row-sub">physio.org.nz — navigate to CPD & Registration</div></div><span class="res-row-arrow">↗</span>
    </a>
  </div>`;

  // Broadcast section for capable staff
  if(canBroadcast()&&!_inserviceReady) loadInservices();
  if(canBroadcast()){
    html+=`<div class="section" style="margin-bottom:12px">
      <div class="section-title">📅 Inservice → CPD Broadcast</div>
      <div id="cpd-broadcast-section">${buildInserviceHtml()}</div>
    </div>`;
  }

  // Add entry button / form
  if(!_cpdShowForm){
    html+=`<div style="text-align:center;margin-bottom:14px"><button class="btn-cpd-add" style="padding:11px 28px" onclick="toggleCPDForm(true)">+ Log CPD Activity</button></div>`;
  } else {
    const today=new Date().toISOString().split("T")[0];
    html+=`<div class="cpd-add-card" style="margin-bottom:14px">
      <div style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:12px">📝 Log new CPD activity</div>
      <div class="cpd-form-row">
        <div class="cpd-form-field" style="grid-column:1/-1">
          <label>Activity title</label>
          <input id="cpd-title" type="text" placeholder="e.g. Dry needling refresher course">
        </div>
      </div>
      <div class="cpd-form-row">
        <div class="cpd-form-field">
          <label>Category</label>
          <select id="cpd-type" onchange="updateCPDType(this.value)">
            ${CPD_CATEGORIES.map(c=>`<option value="${c.key}"${c.key===_cpdFormType?" selected":""}>${c.icon} ${c.label}</option>`).join("")}
          </select>
        </div>
        <div class="cpd-form-field">
          <label>Hours</label>
          <input id="cpd-hours" type="number" min="0.5" step="0.5" placeholder="e.g. 2">
        </div>
      </div>
      ${_cpdFormType==="reflective"?`<div class="cpd-form-row"><div class="cpd-form-field" style="grid-column:1/-1"><label>Reflective statement type (PBNZ requirement)</label><select id="cpd-reflect-sub"><option value="">— Select type —</option><option value="maori">🌿 Māori culture (1 required per year)</option><option value="general">🔄 Culture / Ethics / Professionalism (2 required per year)</option></select></div></div>`:""}
      <div class="cpd-form-row">
        <div class="cpd-form-field">
          <label>Date</label>
          <input id="cpd-date" type="date" value="${today}">
        </div>
        <div class="cpd-form-field">
          <label>Notes (optional)</label>
          <input id="cpd-notes" type="text" placeholder="Provider, certificate no., etc.">
        </div>
      </div>
      <div style="display:flex;align-items:center;flex-wrap:wrap;gap:8px;margin-top:4px">
        <button class="btn-cpd-add" onclick="addCPDEntry()">Save activity</button>
        <button class="btn-cpd-cancel" onclick="toggleCPDForm(false)">Cancel</button>
      </div>
      <div style="margin-top:12px;border-top:1px solid var(--border);padding-top:12px">
        <div style="font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.06em;margin-bottom:7px">Supporting document (optional)</div>
        <div style="border:1.5px dashed var(--border);border-radius:8px;padding:12px;text-align:center;cursor:pointer;transition:border-color .15s" onclick="document.getElementById('cpd-new-doc').click()" onmouseover="this.style.borderColor='var(--accent)'" onmouseout="this.style.borderColor='var(--border)'">
          <span id="cpd-new-doc-label" style="font-size:12px;color:var(--muted)">📎 Attach certificate, screenshot or PDF</span>
          <input id="cpd-new-doc" type="file" accept="image/*,application/pdf" style="display:none" onchange="handleNewCPDDocSelect(this)">
        </div>
      </div>
    </div>`;
  }

  // Entry list
  if(_cpdEntries.length===0){
    html+=`<div class="empty-state"><div class="empty-state-icon">📋</div><div class="empty-state-title">No CPD logged yet</div><div class="empty-state-sub">Tap "Log CPD Activity" above to get started.<br>All entries are saved to your TBP portal profile.</div></div>`;
  } else {
    // Group by month
    const byMonth={};
    _cpdEntries.forEach(e=>{
      const m=e.date?e.date.substring(0,7):"Unknown";
      if(!byMonth[m])byMonth[m]=[];
      byMonth[m].push(e);
    });
    Object.keys(byMonth).sort().reverse().forEach(month=>{
      const label=month==="Unknown"?"Unknown date":new Date(month+"-01").toLocaleDateString("en-NZ",{month:"long",year:"numeric"});
      const mHrs=byMonth[month].reduce((a,e)=>a+e.hours,0);
      html+=`<div style="font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.07em;margin:14px 0 8px;display:flex;justify-content:space-between"><span>${label}</span><span>${mHrs.toFixed(1)}h</span></div>`;
      byMonth[month].forEach(e=>{
        const cat=CPD_CATEGORIES.find(c=>c.key===e.type)||{icon:"➕",label:"Other"};
        const docHtml = e.docUploading
          ? `<div style="margin-top:5px;font-size:10px;color:var(--blue)">⏳ Uploading…</div>`
          : e.docName
            ? `<div style="margin-top:5px;display:flex;align-items:center;gap:5px;flex-wrap:wrap">
                 <span style="font-size:10px;color:var(--dim)">📎 ${e.docName}</span>
                 <button class="cert-btn view" style="font-size:10px;padding:2px 8px" onclick="viewCPDDoc('${e.id}')">View</button>
                 <button class="cert-btn remove" style="font-size:10px;padding:2px 8px" onclick="removeCPDDoc('${e.id}')">×</button>
               </div>`
            : `<div style="margin-top:5px">
                 <button class="cert-btn upload" style="font-size:10px;padding:3px 10px" onclick="document.getElementById('cpddoc-${e.id}').click()">📎 Attach certificate</button>
                 <input id="cpddoc-${e.id}" type="file" accept="image/*,application/pdf" style="display:none" onchange="handleCPDDocUpload('${e.id}',this)">
               </div>`;
        html+=`<div class="cpd-entry">
          <span class="cpd-entry-icon">${cat.icon}</span>
          <div class="cpd-entry-body">
            <div class="cpd-entry-title">${e.title}</div>
            <div class="cpd-entry-meta">${cat.label}${e.reflective_subtype==="maori"?" 🌿 Māori":e.reflective_subtype==="general"?" 🔄 General":""}${e.date?" · "+new Date(e.date+"T12:00:00").toLocaleDateString("en-NZ"):""}${e.notes?" · "+e.notes:""}</div>
            ${docHtml}
          </div>
          <div style="text-align:right;flex-shrink:0">
            <div class="cpd-entry-hrs">${e.hours}h</div>
            <button class="cpd-entry-del" onclick="removeCPDEntry('${e.id}')" title="Remove">×</button>
          </div>
        </div>`;
      });
    });
  }
  return html;
}

