function toggleEmerg(key){
  if(_expandedEmerg.has(key)) _expandedEmerg.delete(key);
  else _expandedEmerg.add(key);
  renderOrgDocsSection();
}

async function loadInservices(){
  try{
    const all=await readFullLog();
    _inservices=all.filter(e=>!e.type||e.type==="inservice");
  }catch(e){}
  _inserviceReady=true; renderOrgDocsSection();
}

async function broadcastInservice(){
  if(!_isForm.topic.trim()||!_isForm.hours||!_isForm.selected.size){alert("Please fill in Topic and Hours and select at least one staff member.");return;}
  _isForm.sending=true; _isForm.msg=""; renderOrgDocsSection();
  const targets=[..._isForm.selected];
  const entry={
    id:Date.now().toString(), date:_isForm.date,
    topic:_isForm.topic.trim(), title:_isForm.topic.trim()+" [Inservice]",
    type:"inservice", hours:parseFloat(_isForm.hours)||1,
    notes:_isForm.notes.trim(), loggedTo:targets,
    loggedAt:new Date().toISOString(), addedBy:"owner"
  };
  let msgText="❌ Failed to save";
  try{
    const all=await readFullLog();
    all.unshift(entry);
    const s=await writeFullLog(all);
    if(s.ok){
      _inservices.unshift(entry);
      msgText=`✅ Logged for ${targets.length} staff`;
    } else {
      const err=await s.json().catch(()=>({}));
      msgText=`❌ Save failed (${s.status}): ${err.error||"unknown"}`;
    }
  }catch(e){msgText="❌ Error: "+e.message;}
  _isForm={date:new Date().toISOString().slice(0,10),topic:"",hours:"1",notes:"",selected:new Set(STAFF_PRACS.map(p=>p.id)),sending:false,msg:msgText};
  renderOrgDocsSection();
}

function toggleInserviceStaff(pid){
  if(_isForm.selected.has(pid)) _isForm.selected.delete(pid);
  else _isForm.selected.add(pid);
  renderOrgDocsSection();
}

function updateIsForm(field,val){_isForm[field]=val;}

