// ── LOAD 4-WEEK TREND ─────────────────────────────────────────
const REBOOK_API = "/api/rebook-rate"; // same Vercel project as weekly-stats

async function fetchRebookRate(clinikoPracId){
  try{
    const url=REBOOK_API+"?clinikoPracId="+encodeURIComponent(String(clinikoPracId))+"&weekOffset="+APP.weekOffset;
    const res=await fetch(url,{headers:{Authorization:"Bearer "+APP.token}});
    const d=await res.json();
    if(!res.ok){APP.rebookRateError=d.error||("HTTP "+res.status);return null;}
    APP.rebookRateError=null;
    return d.rebookRate??null;
  }catch(e){APP.rebookRateError=e.message;return null;}
}

async function loadMyRebookRate(){
  if(!APP.data?.practitioners?.length) return;
  const clinikoPracId=APP.data.practitioners[0]?.practitionerId;
  if(!clinikoPracId){APP.rebookRateLoaded=true;if(!APP.loading)render();return;}
  const rate=await fetchRebookRate(clinikoPracId);
  APP.rebookRateLoaded=true;
  if(rate!==null) APP.data.rebookRate=rate;
  if(!APP.loading) render();
}

async function loadAllRebookRates(){
  if(!APP.data?.practitioners?.length) return;
  APP.rebookRates={};
  const pracs=APP.data.practitioners.filter(p=>p.practitionerId);
  for(let i=0;i<pracs.length;i+=4){
    const batch=pracs.slice(i,i+4);
    const results=await Promise.all(batch.map(p=>fetchRebookRate(p.practitionerId).then(r=>({id:p.practitionerId,rate:r}))));
    results.forEach(r=>{ if(r.rate!==null) APP.rebookRates[r.id]=r.rate; });
  }
  APP.rebookRateLoaded=true;
  if(!APP.loading) render();
}

function renderStatsSection(){
  // Just do a full render - stats are embedded in the main dashboard
  if(!APP.loading) render();
}

async function loadStaffTrend(){  if(!APP.data||APP.user?.role==="owner") return;
  const pracs=APP.data.practitioners;
  if(!pracs||!pracs.length) return;
  APP.staffTrendLoading=true; APP.staffTrendErr=null;
  const myIds=new Set(pracs.map(p=>p.practitionerId));
  const maxH=pracs.reduce((a,p)=>a+(p.maxHours||0),0);
  try{
    // Fetch 3 older weeks in PARALLEL instead of sequentially
    const fetches=await Promise.all([3,2,1].map(extra=>
      fetch("/api/weekly-stats?weekOffset="+(APP.weekOffset+extra),{headers:{Authorization:"Bearer "+APP.token}})
        .then(r=>r.ok?r.json():null).catch(()=>null)
    ));
    const weeks=[];
    fetches.forEach((data,i)=>{
      const extra=3-i;
      if(!data) return;
      const mp=data.practitioners.filter(p=>myIds.has(p.practitionerId));
      const wk=mergeWeek(mp.map(p=>p.thisWeek));
      const mh=mp.reduce((a,p)=>a+(p.maxHours||0),0)||maxH;
      weeks.push({label:data.thisWeekLabel||"Week -"+extra,totalPts:wk.totalPts,billableHrs:wk.billableHrs,utilPct:mh>0?Math.round((wk.billableHrs/mh)*100):0,revenue:wk.totalRev});
    });
    // Add current week (already loaded)
    const tw=mergeWeek(pracs.map(p=>p.thisWeek));
    weeks.push({label:APP.data.thisWeekLabel,totalPts:tw.totalPts,billableHrs:tw.billableHrs,utilPct:maxH>0?Math.round((tw.billableHrs/maxH)*100):0,revenue:tw.totalRev});
    APP.staffTrend={weeks};
  }catch(e){APP.staffTrendErr=e.message;}
  APP.staffTrendLoading=false;
  const el=document.getElementById("staff-trend-section");
  if(el) el.innerHTML=buildStaff4WeekHtml();
}

function buildStaff4WeekHtml(){
  if(APP.staffTrendLoading) return`<div style="display:flex;align-items:center;gap:10px;padding:8px 0;color:var(--muted);font-size:12px"><div class="spinner" style="width:18px;height:18px;border-width:2px;margin:0"></div> Loading 4-week data…</div>`;
  if(APP.staffTrendErr) return`<div style="font-size:12px;color:var(--amber);padding:6px 0;line-height:1.6">⚠️ 4-week trend unavailable — ${APP.staffTrendErr}<br><span style="font-size:10px;color:var(--muted)">PracID used: ${APP.data?.practitioners?.[0]?.practitionerId||"none"}</span> <button onclick="APP.staffTrendErr=null;loadStaffTrend()" style="font-size:11px;background:var(--accentL);color:var(--accent);border:none;padding:3px 9px;border-radius:6px;cursor:pointer;margin-left:6px">Retry</button></div>`;
  if(!APP.staffTrend?.weeks?.length) return`<div style="font-size:12px;color:var(--muted);padding:6px 0">4-week data loading… <span style="font-size:10px">(PracID: ${APP.data?.practitioners?.[0]?.practitionerId||"none"})</span> <button onclick="loadStaffTrend()" style="font-size:11px;background:var(--accentL);color:var(--accent);border:none;padding:3px 9px;border-radius:6px;cursor:pointer;margin-left:6px">Load now</button></div>`;
  const weeks=APP.staffTrend.weeks, max=Math.max(...weeks.map(w=>w.totalPts),1);
  const peakPts=Math.max(...weeks.map(w=>w.totalPts));
  const avg=Math.round(weeks.reduce((a,w)=>a+w.totalPts,0)/weeks.length);
  const cur=weeks[weeks.length-1].totalPts;
  const uc=weeks[weeks.length-1].utilPct>=85?"var(--green)":weeks[weeks.length-1].utilPct>=60?"var(--amber)":"var(--red)";

  let html=`<div class="trend4-grid">`;
  weeks.forEach((w,i)=>{
    const ic=i===weeks.length-1, col=w.utilPct>=85?"var(--green)":w.utilPct>=60?"var(--amber)":"var(--red)", sl=w.label.split("\u2013")[0].trim();
    html+=`<div class="trend4-card${ic?" current":""}">
      <div class="trend4-lbl">${ic?"This week":sl}${w.totalPts===peakPts&&!ic?" 🏆":""}</div>
      <div class="trend4-pts">${w.totalPts}</div>
      <div class="trend4-sub">${w.billableHrs}h · <span style="color:${col};font-weight:700">${w.utilPct}%</span></div>
      <div class="trend4-sub">$${w.revenue.toLocaleString()}</div>
      <div class="trend4-bar" style="background:${col}"></div>
    </div>`;
  });
  html+=`</div><div style="font-size:11px;color:var(--dim);margin-top:10px;display:flex;flex-wrap:wrap;gap:12px">
    <span>🏆 Peak: <strong>${peakPts} pts</strong></span>
    <span>📊 Avg: <strong>${avg} pts/wk</strong></span>
    <span style="color:${cur>=avg?"var(--green)":"var(--red)"};font-weight:600">${cur>=avg?"↑":"↓"} ${Math.abs(cur-avg)} vs avg</span>
  </div>`;
  return html;
}

// ── API ───────────────────────────────────────────────────────
async function apiLogin(email,password){
  const res=await fetch("/api/auth",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email,password})});
  const data=await res.json(); if(!res.ok) throw new Error(data.error||"Login failed"); return data;
}
async function apiWeeklyStats(){
  const res=await fetch("/api/weekly-stats?weekOffset="+APP.weekOffset,{headers:{Authorization:"Bearer "+APP.token}});
  const data=await res.json(); if(!res.ok) throw new Error(data.error||"Failed to load stats"); return data;
}

// ── WEEK NAV ──────────────────────────────────────────────────
async function changeWeek(delta){
  const n=APP.weekOffset+delta;
  if(n<0||n===APP.weekOffset||n>52) return;
  APP.weekOffset=n; APP.staffTrend=null; APP.loading=true; render();
  try{const d=await apiWeeklyStats();APP.data=d;APP.loading=false;APP.error=null;}
  catch(e){APP.loading=false;APP.error=e.message;}
  render();
  if(APP.user?.role!=="owner") loadStaffTrend();
}
function goCurrentWeek(){if(APP.weekOffset!==0)changeWeek(-APP.weekOffset);}

function renderWeekNav(){
  const now=APP.weekOffset===0, label=APP.data?APP.data.thisWeekLabel:"…";
  return`<div class="week-nav">
    <button class="week-nav-btn" onclick="changeWeek(1)">← Prev</button>
    <span class="week-nav-label">${label}</span>
    <button class="week-nav-btn"${now?" disabled":""} onclick="changeWeek(-1)">Next →</button>
    ${now?"":'<button class="week-nav-btn today" onclick="goCurrentWeek()">↩ Now</button>'}
  </div>`;
}

// ── HELPERS ───────────────────────────────────────────────────
function pct(c,p){return p===0?(c>0?100:0):Math.round(((c-p)/p)*100);}
function deltaHtml(c,p){const d=pct(c,p),cl=d>=0?"up":"down";return`<span class="delta ${cl}">${d>=0?"↑":"↓"} ${Math.abs(d)}%</span>`;}
function barHtml(v,color){
  const c=color||(v>=85?"var(--green)":v>=60?"var(--amber)":"var(--red)");
  return`<div class="bar-wrap"><div class="bar-bg"><div class="bar-fill" style="width:${Math.min(v,100)}%;background:${c}"></div></div><span class="bar-pct" style="color:${c}">${v}%</span>${v>=85?'<span class="bonus-tag">BONUS</span>':""}</div>`;
}
function capacityNote(pracs){
  const d=pracs.reduce((a,p)=>a+(p.phDeductHrs||0),0);
  return d>0?"🗓 "+d.toFixed(1)+"h deducted for public holiday"+(d>8.5?"s":""):"";
}
function mergeWeek(weeks){
  const m={counts:{accInit:0,accFU:0,accExt:0,accTI:0,accTF:0,grp:0,privInit:0,privFU:0},totalPts:0,billableHrs:0,accRevEst:0,surchargeRev:0,privateRev:0,totalRev:0,dna:0,cancel:0,surchargeIsReal:false,privateIsReal:false};
  for(const w of weeks){
    m.totalPts+=(w.totalPts||0);m.billableHrs+=(w.billableHrs||0);m.accRevEst+=w.accRevEst;m.surchargeRev+=w.surchargeRev;m.privateRev+=w.privateRev;m.totalRev+=w.totalRev;m.dna+=w.dna;m.cancel+=w.cancel;
    if(w.surchargeIsReal)m.surchargeIsReal=true;if(w.privateIsReal)m.privateIsReal=true;
    for(const k in m.counts)m.counts[k]+=(w.counts[k]||0);
  }
  m.billableHrs=Math.round(m.billableHrs*10)/10; return m;
}

// ── PANEL (owner) ─────────────────────────────────────────────
async function openPanel(pracId){
  const pracs=APP.data?APP.data.practitioners.filter(r=>r.practitionerId===pracId):[];
  const pracName=pracs.length>0?pracs[0].name:pracId;
  const clinics=pracs.map(r=>({name:r.clinicName,color:r.clinicColor}));
  APP.panel={open:true,pracId,pracName,clinics,loading:true,trendData:null};
  renderPanel();
  try{
    const res=await fetch("/api/practitioner-trend?pracId="+pracId+"&weekOffset="+APP.weekOffset+"&weeks=4",{headers:{Authorization:"Bearer "+APP.token}});
    const data=await res.json();
    if(!res.ok)throw new Error(data.error||"Failed");
    APP.panel.trendData=data;
  }catch(e){APP.panel.trendData={error:e.message};}
  APP.panel.loading=false; renderPanel();
}
function closePanel(){APP.panel.open=false;renderPanel();}
function renderPanel(){
  const ov=document.getElementById("panel-overlay"), pn=document.getElementById("panel");
  if(!ov||!pn)return;
  if(APP.panel.open){
    ov.classList.add("open");pn.classList.add("open");pn.innerHTML=renderPanelContent();
  }else{ov.classList.remove("open");pn.classList.remove("open");}
  document.querySelectorAll("tr.selected").forEach(r=>r.classList.remove("selected"));
  if(APP.panel.open&&APP.panel.pracId) document.querySelectorAll("tr[data-prac='"+APP.panel.pracId+"']").forEach(r=>r.classList.add("selected"));
}
function renderPanelContent(){
  const p=APP.panel;
  const dots=p.clinics.map(c=>`<span style="display:inline-flex;align-items:center;gap:4px;margin-right:7px"><span class="clinic-dot" style="background:${c.color}"></span>${c.name}</span>`).join("");
  let h=`<div class="panel-head"><div><div class="panel-name">${p.pracName}</div><div class="panel-clinic">${dots}</div></div><button class="panel-close" onclick="closePanel()">&#x2715;</button></div><div class="panel-body">`;
  if(p.loading){h+=`<div class="loading-panel"><div class="spinner"></div><div>Loading…</div></div></div>`;return h;}
  if(!p.trendData||p.trendData.error){h+=`<p style="color:var(--red)">${p.trendData?p.trendData.error:"No data"}</p></div>`;return h;}
  const weeks=p.trendData.weeks, latest=weeks[weeks.length-1], maxPts=Math.max(...weeks.map(w=>w.totalPts),1), peakPts=Math.max(...weeks.map(w=>w.totalPts));
  h+=`<div class="panel-section"><div class="panel-section-title">4-Week Summary</div><div class="trend-grid">`;
  weeks.forEach((w,i)=>{
    const ic=i===weeks.length-1, sl=w.label.split("\u2013")[0].trim(), uc=w.utilPct>=85?"var(--green)":w.utilPct>=60?"var(--amber)":"var(--red)";
    h+=`<div class="trend-week${ic?" current":""}"><div class="trend-week-label">${sl}${w.totalPts===peakPts?" 🏆":""}</div><div class="trend-val">${w.totalPts}</div><div class="trend-sub">${w.billableHrs}h · <span style="color:${uc};font-weight:600">${w.utilPct}%</span></div><div class="trend-sub">$${w.revenue.toLocaleString()}</div></div>`;
  });
  h+=`</div><div class="chart-wrap">`;
  weeks.forEach((w,i)=>{
    const ic=i===weeks.length-1, pp=Math.round((w.totalPts/maxPts)*100), col=ic?"var(--accent)":"var(--accentL)";
    h+=`<div class="chart-bar-group"><span style="font-size:10px;color:var(--dim)">${w.totalPts}</span><div class="chart-bar-outer" style="height:55px"><div style="width:100%;height:${pp}%;background:${col};border-radius:3px;position:absolute;bottom:0"></div></div><div class="chart-label">${w.label.split("\u2013")[0].trim()}</div></div>`;
  });
  h+=`</div></div>`;
  h+=`<div class="panel-section"><div class="panel-section-title">This Week — Detail</div><div class="mini-grid">`;
  h+=mini2("ACC Initial",latest.counts.accInit)+mini2("ACC Follow-up",latest.counts.accFU)+mini2("Extended/Other",latest.counts.accExt+(latest.counts.accTI||0)+(latest.counts.accTF||0))+mini2("Private",latest.counts.privInit+latest.counts.privFU)+mini2("Group",latest.counts.grp)+mini2("DNA/Cancel",latest.dna+" / "+latest.cancel,latest.dna>2?"var(--redBg)":null,latest.dna>2?"var(--red)":null);
  h+=`</div></div>`;
  h+=`<div class="panel-section"><div class="panel-section-title">Revenue per Week</div><div style="display:grid;grid-template-columns:repeat(4,1fr);gap:7px">`;
  weeks.forEach((w,i)=>{
    const ic=i===weeks.length-1;
    h+=`<div style="background:${ic?"var(--accentL)":"#fafbfa"};border-radius:8px;padding:9px"><div style="font-size:9px;color:var(--muted);text-transform:uppercase;margin-bottom:3px">${w.label.split("\u2013")[0].trim()}</div><div style="font-size:14px;font-weight:700">$${w.revenue.toLocaleString()}</div><div style="font-size:10px;color:var(--dim)">${w.totalPts} pts</div></div>`;
  });
  h+=`</div></div></div>`;
  return h;
}
function mini2(label,val,bg,color){
  return`<div style="background:${bg||"#fafbfa"};border-radius:8px;padding:10px"><div class="mini-label" style="color:${color||"var(--muted)"}">${label}</div><div class="mini-val" style="color:${color||"var(--text)"}">${val}</div></div>`;
}


// ── AUDITS ────────────────────────────────────────────────────
let _audits=[], _auditsReady=false;
let _auditForm={type:"hs_audit",clinic:"titirangi",date:new Date().toISOString().slice(0,10),checks:{},itemNotes:{},physioAudited:"",overallNotes:"",sending:false,msg:""};

async function loadAudits(){
  // Try Google Drive with timeout (avoids iOS Safari hang)
  const driveState = await _driveWithTimeout(()=>_kpiLoadDriveState());
  if(driveState && Array.isArray(driveState.audits)){
    _audits = driveState.audits;
    _auditsReady=true; renderAuditsSection();
    return;
  }
  // Drive unavailable — fall back to Vercel
  try{
    const r=await fetch(PORTAL_API+"/store",{headers:{"X-Portal-Secret":PORTAL_SECRET}});
    if(r.ok){
      const state=await r.json();
      const all={...(state.files||{}),...(state.data||{})};
      _audits=Array.isArray(all["audits"])?all["audits"]:[];
    }
  }catch(e){_warn("[Audits Vercel]",e.message);}
  _auditsReady=true; renderAuditsSection();
}

function renderAuditsSection(){const el=document.getElementById("audits-section");if(el)el.innerHTML=buildAuditsHtml();}

function updateAuditForm(field,val){_auditForm[field]=val; renderAuditsSection();}
function updateAuditResponse(key,val){_auditForm.checks[key]=val; renderAuditsSection();}
function updateAuditType(t){_auditForm={type:t,clinic:_auditForm.clinic,date:_auditForm.date,checks:{},itemNotes:{},physioAudited:"",overallNotes:"",sending:false,msg:""};renderAuditsSection();}

